
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Bus, UserCog, User, ShieldCheck, LogIn } from "lucide-react";
import Link from 'next/link';
import { cn } from '@/lib/utils';

export default function LoginPage() {
  const router = useRouter();
  const { toast } = useToast();
  const [role, setRole] = useState('parent');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API call
    setTimeout(() => {
      if ((role === 'admin' && email === 'admin@yellowtransit.com') ||
          (role === 'driver' && email === 'driver@yellowtransit.com') ||
          (role === 'parent' && email === 'parent@yellowtransit.com')) {
        
        toast({
          title: "Login Successful",
          description: `Welcome! Redirecting to the ${role} dashboard.`,
        });
        
        // In a real app, you'd handle session/token here
        router.push(`/dashboard/${role}`);

      } else {
        toast({
          variant: 'destructive',
          title: "Login Failed",
          description: "Invalid email or password for the selected role.",
        });
        setIsLoading(false);
      }
    }, 1000);
  };
  
  const fillDemoCredentials = () => {
      const credentials = {
          parent: 'parent@yellowtransit.com',
          admin: 'admin@yellowtransit.com',
          driver: 'driver@yellowtransit.com'
      }
      setEmail(credentials[role as keyof typeof credentials]);
      setPassword('password');
  }

  return (
    <div className="relative flex min-h-screen flex-col items-center justify-center bg-background p-4">
       <div 
        className="absolute inset-0 w-full h-full bg-cover bg-center" 
        style={{backgroundImage: "url('https://placehold.co/1920x1080.png')", backgroundPosition: 'center'}}
        data-ai-hint="yellow school bus"
       >
       </div>

       <div className="absolute top-4 left-4 z-10 hidden md:flex">
        <Link href="/" className="flex items-center justify-center gap-2 text-white">
            <Bus className="h-6 w-6 text-primary" />
            <span className="text-lg font-semibold font-headline">Yellow Transit</span>
        </Link>
      </div>

      <Card className="w-full max-w-sm z-10 bg-white/95 backdrop-blur-sm text-card-foreground shadow-2xl rounded-2xl">
        <CardHeader className="text-center space-y-4">
            <div className="mx-auto bg-primary/20 text-primary p-3 rounded-full w-fit">
                <Bus className="h-8 w-8" />
            </div>
            <div className="space-y-1">
                <CardTitle className="text-2xl font-bold font-headline">Yellow Transit</CardTitle>
                <CardDescription className="text-muted-foreground">School Bus Management System</CardDescription>
            </div>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
                <Label>Login as:</Label>
                <div className="grid grid-cols-3 gap-2">
                    <Button type="button" variant={role === 'parent' ? 'default' : 'outline'} onClick={() => setRole('parent')}>Parent</Button>
                    <Button type="button" variant={role === 'admin' ? 'default' : 'outline'} onClick={() => setRole('admin')}>Admin</Button>
                    <Button type="button" variant={role === 'driver' ? 'default' : 'outline'} onClick={() => setRole('driver')}>Driver</Button>
                </div>
            </div>
            <div className="space-y-2">
              <Label htmlFor="email">Email Address</Label>
              <Input id="email" type="email" placeholder="Enter your email" required value={email} onChange={e => setEmail(e.target.value)} disabled={isLoading} />
            </div>
            <div className="space-y-2">
              <Label htmlFor="password">Password</Label>
              <Input id="password" type="password" placeholder="Enter your password" required value={password} onChange={e => setPassword(e.target.value)} disabled={isLoading} />
            </div>
            <Button type="submit" className="w-full" disabled={isLoading}>
              {isLoading ? 'Signing In...' : 'Sign In'}
            </Button>
          </form>
           <div className="mt-4 text-center">
                <p className="text-xs text-muted-foreground mb-2">Demo Mode - Try different roles:</p>
                <Button variant="link" className="text-xs h-auto p-0" onClick={fillDemoCredentials}>Fill Demo Credentials for {role.charAt(0).toUpperCase() + role.slice(1)}</Button>
            </div>
        </CardContent>
      </Card>
       <div className="absolute bottom-4 text-center z-10">
          <p className="text-xs text-white/80">
            © 2025 Yellow Transit. Enhancing school transport safety in Kenya.
          </p>
        </div>
    </div>
  );
}
